import base64, subprocess

B64 = ""

content = base64.b64decode(B64)
with open("bms_mobile.html", "wb") as f:
    f.write(content)
print("Arquivo atualizado!")

subprocess.run(["git", "add", "bms_mobile.html"])
subprocess.run(["git", "commit", "-m", "BMS Mobile - caldeira com chama animada"])
result = subprocess.run(["git", "push"], capture_output=True, text=True)
print(result.stdout or result.stderr)
print("Deploy concluido!" if result.returncode == 0 else "Erro no push")
